    #[test]
    fn discover_configs_finds_nearest_first() {
        let root = TempDir::new().unwrap();

        // Create root-level .shatter/config.yaml
        let root_shatter = root.path().join(".shatter");
        fs::create_dir_all(&root_shatter).unwrap();
