/// Convention-discovered setup files for a project.
#[derive(Debug, Clone, Default, PartialEq)]
pub struct DiscoveredSetupFiles {
    /// Session-level setup file: `shatter.setup.{ext}` in project root,
    /// or `.shatter/setup.{ext}`.
    pub session_setup: Option<PathBuf>,

    /// File-level setup files: source file path → co-located `<stem>.shatter.setup.{ext}`.
    pub file_setups: HashMap<PathBuf, PathBuf>,
}

/// Discover setup files by naming convention.
///
/// Convention locations:
/// - **Session**: `{project_root}/shatter.setup.{ext}` (preferred) or
///   `{project_root}/.shatter/setup.{ext}` (fallback)
/// - **File-level**: `<stem>.shatter.setup.{ext}` co-located with each source file
///
/// If `config` specifies explicit setup entries (`defaults.session_setup` or
/// `defaults.file_setup`), the corresponding convention discovery is skipped.
pub fn discover_setup_files(
    project_root: &Path,
    language_ext: &str,
    config: &ShatterConfig,
) -> DiscoveredSetupFiles {
    let mut result = DiscoveredSetupFiles::default();

    // Session-level discovery (skip if config specifies session_setup).
    if config.defaults.session_setup.is_none() {
        // Prefer project_root/shatter.setup.{ext}
        let root_session = project_root.join(format!("shatter.setup.{language_ext}"));
        if root_session.is_file() {
            result.session_setup = Some(root_session);
        } else {
            // Fallback: .shatter/setup.{ext}
            let dot_session = project_root.join(".shatter").join(format!("setup.{language_ext}"));
            if dot_session.is_file() {
                result.session_setup = Some(dot_session);
            }
        }
    }

    // File-level discovery (skip if config specifies file_setup).
    if config.defaults.file_setup.is_none() {
        discover_file_setups(project_root, language_ext, &mut result.file_setups);
    }

    result
}

/// Recursively find `<stem>.shatter.setup.{ext}` files under `dir` and record
/// the source file they correspond to.
fn discover_file_setups(dir: &Path, ext: &str, file_setups: &mut HashMap<PathBuf, PathBuf>) {
    let entries = match std::fs::read_dir(dir) {
        Ok(entries) => entries,
        Err(_) => return,
    };

    let setup_suffix = format!(".shatter.setup.{ext}");

    for entry in entries.flatten() {
        let path = entry.path();
        if path.is_dir() {
            // Skip .shatter directories and hidden directories
            if let Some(name) = path.file_name().and_then(|n| n.to_str()) {
                if !name.starts_with('.') {
                    discover_file_setups(&path, ext, file_setups);
                }
            }
        } else if let Some(name) = path.file_name().and_then(|n| n.to_str()) {
            if let Some(stem) = name.strip_suffix(&setup_suffix) {
                if !stem.is_empty() {
                    // Map back to the source file: same directory, stem + .{ext}
                    let source_file = dir.join(format!("{stem}.{ext}"));
                    file_setups.insert(source_file, path.clone());
                }
            }
        }
    }
}

